#include <stdio.h>

int buscar(const int datos[], int n, int objetivo) {
    for (int i = 0; i < n; i++) {
        if (datos[i] == objetivo) {
            return i;
        }
    }
    return -1;
}

int main(void) {
    int datos[] = {7, 4, 9, 2, 5};
    int pos = buscar(datos, 5, 2);
    printf("Posicion: %d\n", pos);
    return 0;
}

